var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"어머, 무슨 그런 말씀을.","JPN":"まあ、なんてもったいないお言葉。","ENG":"Oh my, you’re making me blush.","TWN":"哎呀，這麼客氣。"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님. 과찬이세요. 그 정도야 제겐 일도 아니니까요.","JPN":"ヘイブン様、褒めすぎです。このくらい、私にはどうってこともないのですから。","ENG":"Mr. Haven, you’re too kind. It was no trouble on my part.","TWN":"天堂先生過獎，那點小事對我而言不算什麼。"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래요? 그럼 당신이 이룩한 <color=#ffd34c>헤이븐 랜드</color>……","JPN":"そうですか？　それでは、あなたが築いてきた<color=#ffd34c>ヘイブンランド</color>……","ENG":"Is that so? Then <color=#ffd34c>Havenland</color> and what you’ve accomplished...","TWN":"是嗎？那您建立的<color=#ffd34c>天堂樂園</color>……"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아니, 당신의 이름을 팔아 제가 직접 쌓아 올린 나의 <color=#ffd34c>헤이븐 랜드</color>를……","JPN":"いいえ、あなたの名をかたって私が直接築いてきた私の<color=#ffd34c>ヘイブンランド</color>を……","ENG":"No, \\"my\\" <color=#ffd34c>Havenland</color> that \\"I\\" founded using your name...","TWN":"不對，您只是掛名而已，<color=#ffd34c>天堂樂園</color>是我親手建立起來的……"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이렇게.","JPN":"こうやって。","ENG":"How...!","TWN":"像這樣…"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이렇게.","JPN":"こうやって。","ENG":"Could...!","TWN":"這樣…"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이렇……","JPN":"こう……","ENG":"Y-!","TWN":"這……"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이게…… 이게 지금…….","JPN":"これ……これはいったい……","ENG":"What... have I...?","TWN":"我……我現在……"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"내가 무슨 짓을…….","JPN":"私、なんてことを……","ENG":"What have I done...?!","TWN":"這是在做什麼……"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"꺄하하하! 이게 헤이븐 님께서 말한 그 재미인가요? 그런가요?!","JPN":"キャハハハ！　これがヘイブン様がおっしゃった楽しさなのですか？　そうなんですか！？","ENG":"Kyahahaha! Is this the \\"entertainment\\" Mr. Haven mentioned? Is it?!","TWN":"哈哈哈哈！這就是天堂先生說的興趣嗎？是嗎？！"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"난… 그렇게 웃지 않아. 이건 내가 아니야. 내가 그런 게 아니야……!","JPN":"私は……そんな風に笑わないわ。これは私じゃない。私がやったんじゃない……！","ENG":"No... I don't laugh like that. This isn't me. I didn't do anything...!","TWN":"我…我沒有笑，那不是我，我沒有……！"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L23_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……다 없어졌네.","JPN":"……全部消えたわね。","ENG":"It's... all over.","TWN":"我現在變得一無所有……"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하늘 위에서… 땅바닥 아래로 쿵… 처박혀 버렸어.","JPN":"空の上から……地面の下にドンと……めり込んでしまった。","ENG":"It fell... from the sky... and crashed.","TWN":"從天堂…落入凡間…"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"휴. 어쩔 수 없지.","JPN":"はあ。仕方ないわね。","ENG":"*Sigh* Oh well.","TWN":"哀，沒辦法。"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"가방도 팔고… 모자도 팔고… 구두도 팔고… 옷도 팔고… 또 뭘 팔지?","JPN":"かばんも売って……帽子も売って……靴も……服も売って……他に何を売る？","ENG":"I guess I'll just have to sell my bags, hats, boots, clothes, and... What else can I sell?","TWN":"只好賣包包…賣帽子…賣鞋子…賣衣服…還有什麼可以賣？"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"팔 수 있는 거 다 팔아서……","JPN":"売れるもの、全部売って……","ENG":"I just have to sell everything...","TWN":"能賣的全都賣掉……"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님께만 잘 보이면 돼.","JPN":"ヘイブン様にさえよく映ればいい。","ENG":"And make sure Mr. Haven notices me.","TWN":"只能討天堂先生開心就好。"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"개 같이 고생했던 그때로 돌아가서 개처럼 살다가 하늘로 올라가는 거야.","JPN":"死ぬほど苦労したあの時に戻って、犬のように生きて、空に這い上がるの。","ENG":"I'll go back to how I worked like a slave until I finally reach the sky.","TWN":"先回去過那種像豬狗不如的生活，之後一定可以再回到天堂的！"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L33_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……안 돼. 아, 안 돼! 내 <color=#ffd34c>헤이븐 랜드</color>… 내 거 돌려놔!!","JPN":"……ダメ。だ、ダメ！　私の<color=#ffd34c>ヘイブンランド</color>……私のものを返して！！","ENG":"N-no... NO!! My <color=#ffd34c>Havenland</color>... Give it back!!","TWN":"……不行！不可以！<color=#ffd34c>天堂樂園</color>是我的…把我的東西還來！！"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L34_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"돌려 놓으라고!!!","JPN":"返してよ！！","ENG":"It's mine!","TWN":"還給我！！！"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"으아악!! 사, 살려줘!","JPN":"あああ！！　た、助けて！","ENG":"Aaaaack!! H-help me!","TWN":"呃啊啊！！救我！"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L38_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아직 안 끝났어! 되돌릴 수 있다고! 제발 날 놔줘!!","JPN":"まだ終わってない！　取り返せるわ！　お願いだから離して！！","ENG":"It can't be over for me! I can undo it! Please, let me go!!","TWN":"還沒結束！我會東山再起的！放開我！！"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L42_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"제발…… 이거 놔……!!","JPN":"お願い……離して……！！","ENG":"Please... Let go...!!","TWN":"拜託……放開……！！"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"으아악!","JPN":"あああ！","ENG":"Aaack!","TWN":"呃啊啊！！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"마담! 무슨 일이십니까!","JPN":"マダム！　どうなさいましたか！","ENG":"Madam! What's wrong?!","TWN":"夫人！發生什麼事？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하아… 하아……. 아, 악몽을…….","JPN":"はあ……はあ……あ、悪夢を……","ENG":"*Huff... Huff...* Oh, just a nightmare...","TWN":"呼呼…呼呼……我做惡夢……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"아. 꿈을 꾸셨군요.","JPN":"あ。夢を見られたのですね。","ENG":"Oh, you were dreaming.","TWN":"原來是做夢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그냥 꿈이 아니라 악몽이라고! 못 알아 들어?!","JPN":"ただの夢じゃなくて悪夢よ！　言ったでしょう！？","ENG":"It wasn't a dream. It was a nightmare! Didn't you hear me?!","TWN":"不是做夢，是做惡夢！聽不懂人話嗎？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그 빌어먹을 악몽 때문에 한 시간도 편히 못 잔단 말이야!! 한 시간도!!","JPN":"あのクソ悪夢のせいで、1時間も安らかに眠れない！！　1時間も！！","ENG":"I can't get an ounce of sleep because of that retched nightmare!! Aargh!!","TWN":"因為那該死的惡夢，我沒有一刻是能睡好覺的！！完全沒有！！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"아래에서 너무 고생을 많이 하셨습니다. 좀 더 쉬시는 게 좋을 것 같군요.","JPN":"下でご苦労が多すぎたのでしょう。もう少しお休みになった方がよろしいかと。","ENG":"You seem stressed from working down under. You should get some rest ma'am.","TWN":"您可能在下面太過操勞，再多休息一會兒吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……아니에요. 고생은 여러분들이 했죠.","JPN":"……いいえ。皆さんの方が苦労したでしょう。","ENG":"No... It's all of you who did the hard work.","TWN":"……不，辛苦的是你們。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"미안해요. 악몽을 꿨더니 좀 예민해져서.","JPN":"ごめんなさい。悪夢を見てすこし神経質になってしまって。","ENG":"My apologies. I'm just a little groggy from the nightmare.","TWN":"抱歉，做惡夢後變得有些易怒。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"위저드 부지는 어떻게 됐나요? 재사용 가능할까요?","JPN":"ウィザードの敷地はどうなりましたか？　また使用できるのでしょうか。","ENG":"What happened to the Wizard grounds? Is it reusable?","TWN":"魔法師的據點現在怎麼樣？有辦法重複利用嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"어려울 것 같습니다.","JPN":"難しいと思います。","ENG":"I'm afraid not, ma'am.","TWN":"似乎沒辦法。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"폭발 때문에 잔해에 파묻힌 데다가, 관리국에서 조사가 나와 허위 명의로 된 부지인 것이 밝혀진 모양입니다.","JPN":"爆発の影響で残骸に埋もれたうえに、管理局による調査が始まって偽名義の敷地であることが明るみに出たようです。","ENG":"The explosion left everything in rubble. Plus, the Administration started an investigation and found out it was registered to an alias.","TWN":"炸毀後，整個都埋在碎石頭底下，再加上管理局出面調查，結果被發現建築物持有人的姓名是假的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……영악한 것들. 곧바로 관리국에 알렸나 보군요.","JPN":"……小賢しい。すぐ管理局に知らせたようですね。","ENG":"Those manipulative brats...! They must've reported it to the Administration.","TWN":"……真是機靈的丫頭，竟然這麼快就告訴管理局。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"당장 조직원 풀어 잡아오겠습니다.","JPN":"すぐ組織員を送って捕まえてきます。","ENG":"Shall I send some of our members down to catch them?","TWN":"我們立刻派人去逮人！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그럴 필요 없어요. 알아서 기어 올라올 거니까.","JPN":"その必要はありません。あちらから這い上がってくるでしょうから。","ENG":"No need. They'll be crawling up to us soon...","TWN":"不需要，她們會自己找上門來的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"예?","JPN":"はい？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"알아서 올 거라니까 아까부터 말귀를 못 알아먹어?!","JPN":"あちらから来るって言ってるのに理解できないの！？","ENG":"I said, they'll be boarding the ship! Don't make me repeat myself!","TWN":"我說她們會自己找上門，你耳朵是耳屎太多嗎？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"……죄송합니다.","JPN":"……申し訳ございません。","ENG":"...My apologies, Madam.","TWN":"……抱歉！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"휴. 그만 나가 봐요. 좀 쉬어야겠어요.","JPN":"ふう。もう出ていってください。少し休みます。","ENG":"*Sigh...* You can leave now. I need my rest.","TWN":"呼，出去吧，我要休息一下。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"아. 네. 쉬십시오, 마담.","JPN":"あ。はい。お休みなさいませ、マダム。","ENG":"Y-yes, Madam. I'll leave immediately.","TWN":"是，夫人請好好休息。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님께는 뭐라고 말씀드려야 하나.","JPN":"ヘイブン様にはなんとお伝えすればいいのかしら。","ENG":"What do I tell Mr. Haven...?","TWN":"該怎麼跟天堂先生解釋才好。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……말씀드린다고 제대로 들어 주실지 모르겠네. 노는 것 말곤 관심도 없으신 분이니.","JPN":"……言ってもちゃんと聞いてくださるかしら。遊び以外には興味のない方なんだから。","ENG":"Even if I do tell him, he isn't going to listen. All he's interested in is fooling around.","TWN":"……就算解釋他也不一定會聽，他只對好玩的事感興趣。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"이대로는 안 돼. 마냥 기다렸다가 선수를 뺏길 수도 있어.","JPN":"このままではいけないわ。待っているだけでは、先手を打たれる可能性もあるもの。","ENG":"I can't just stand around like this. I can't let them beat me to it.","TWN":"這樣不行，我不能坐以待斃，必須先發制人！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"절대로, 모래 알갱이 한 알 떨어지지 않도록 견고하게 내 성을 쌓아 올려야 돼.","JPN":"絶対に、砂一粒も落ちないように、私の城をもっと頑丈に築いておかないと。","ENG":"Absolutely not. I need to fortify my castle so not even a grain of sand falls off.","TWN":"我要打造堅固的堡壘，連一隻蒼蠅都不能飛進來！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"좀 무리해서라도 함선 보수를 다시 하고, 병력을 늘리면 제까짓 것들이 뭘 할 수 있겠어?","JPN":"少し無理してでも艦船を補修して、兵を増やせばあの小娘たちだって何もできないはずよ。","ENG":"Even though it'll cost me, what can those brats do if I reinforce the ship and hire more security?","TWN":"雖然有點吃力，還是必須重新修復艦船，再增加兵力，這樣她們應該也拿我沒辦法吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"게다가…… 아직 <color=#ffd34c>그것</color>도 남아있지.","JPN":"それに……まだ<color=#ffd34c>あれ</color>も残っていることだし。","ENG":"Also... I still have <color=#ffd34c>that</color>.","TWN":"況且……我還有<color=#ffd34c>那個</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"예정보다 일러도, 그 맹랑한 것들 잡으려면 <color=#ffd34c>그걸</color> 작동시키는 수밖에.","JPN":"予定より早くても、あの小娘たちを捕まえるには<color=#ffd34c>あれ</color>を使うしかないわね。","ENG":"I wasn't planning on activating <color=#ffd34c>it</color> so soon, but I have no choice if I want to catch those rascals...","TWN":"雖然比預期的時間要早，但要對付她們，就只能啟動<color=#ffd34c>那個</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"감히 내 것에 손을 대다니…… 못된 아이들은 벌을 받아야지.","JPN":"身のほども知らず私のものに手を出すなんて……悪い子はお仕置きしてあげないと。","ENG":"How dare they lay their hands on my things...! These naughty kids need to be punished!","TWN":"竟敢碰我的東西……不乖的孩子當然要受懲罰。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"오늘은…… 라스트 헤이븐에 가서 독한 칵테일이라도 한 잔 마셔야겠어…….","JPN":"今日は……ラストヘイブンで強いカクテルでも一杯飲もう……","ENG":"But tonight... I need get to Last Haven and get myself a strong cocktail...","TWN":"我今天……必須去最後的天堂喝杯烈酒才行……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"피곤해……. 큭, 그 빌어먹을 꼬맹이들……!","JPN":"疲れた……くっ、あのクソガキども……！","ENG":"I'm so exhausted... Krrgh...! If it weren't for those meddling kids...!","TWN":"真是累人……可惡，都是那些該死的丫頭……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};